body:
I have a half-adder module like this:
```
module halfadder(output logic ha_sum, output ha_carry_out, input logic ha_a, input ha_b);
      assign ha_sum = ha_a ^ ha_b;
      assign ha_carry_out  = ha_a & ha_ha_b;
endmodule
```
and it's corresponding testbench as shown below
```
`include "halfadder.sv"

module tb_halfadder();
    // test vector
    logic [3:0] testvector [3:0];
    // inputs and outputs
    logic ha_a;
    logic ha_b;
    logic ha_sum;
    logic ha_carry_out;

    // design unit instantiation
    halfadder ha(.ha_sum(ha_sum), .ha_carry_out(ha_carry_out), .ha_a(ha_a), .ha_b(ha_b));

    initial begin
        $readmemb("ha_testcases", testvector, 0, 3);
        assertOutput();
    end

    task assertOutput;
        begin
            for (int i = 0; i < 4; i++) begin
                {ha_a, ha_b, expected_sum, expected_carry_out} = testvector[i];
                #5;
                if (ha_a == 1'b0 && ha_b == 1'b0 && ha_sum == 1'b0 && ha_carry_out == 1'b0) $display("1");
                else if (ha_a == 1'b0 && ha_b == 1'b1 && ha_sum == 1'b1 && ha_carry_out == 1'b0) $display("1");
                else if (ha_a == 1'b1 && ha_b == 1'b0 && ha_sum == 1'b1 && ha_carry_out == 1'b0) $display("1");
                else if (ha_a == 1'b1 && ha_b == 1'b1 && ha_sum == 1'b0 && ha_carry_out == 1'b1) $display("1");
                else $display("0");
            end
        end
    endtask

endmodule
```

But I am getting the below errors.
```
./halfadder.sv:1: warning: Port declaration of ha_sum inherits dimensions from var/net.
sh: 1: vpphalfadder.out: not found
./halfadder.sv:1: warning: Port declaration of ha_sum inherits dimensions from var/net.
/home/michael/CLionProjects/GeLayeredFullAdder/tb_halfadder.sv:10: vvp.tgt error: uwire "ha_carry_out" must have a single driver, found (2).
error: Code generation had 1 error(s).
./halfadder.sv:1: warning: Port declaration of ha_sum inherits dimensions from var/net.
sh: 1: vpphalfadder.out: not found
./halfadder.sv:1: warning: Port declaration of ha_sum inherits dimensions from var/net
```

What could be wrong?

